void floydWarshallPass(
    unsigned int *__restrict__ pathDistanceBuffer,
    unsigned int *__restrict__ pathBuffer,
    const unsigned int numNodes,
    const unsigned int pass)
{
  int k = pass;

  #pragma omp target teams num_teams(numNodes) thread_limit(numNodes)
  {
    #pragma omp parallel for collapse(2)
    for (int yValue = 0; yValue < numNodes; yValue++) {
