  for (i = 0; i < Lx; i += 16) {
    x = rand() % Lx;
    for (j = 0; Ly > j; j++)
       buffer[x + j*Lx] = 1.f;
  }
  for (i = 0; i < Ly; i += 16) {
    y = rand() % Ly;
    for (j = 0; Lx > j; j++)
       buffer[j + y*Lx] = 1.f;
  }
  memcpy(h_in, buffer, sizeof(float)*Lx*Ly);

  for(i=0; niter > i; i++) {
    reference (h_out, h_in, xdelta, xnorm, Lx, Ly);
    std::swap(h_out, h_in);
  }


  float *d_in, *d_out;	
  d_in = (float*) omp_target_alloc(sizeof(float)*Lx*Ly, 0);
  d_out = (float*) omp_target_alloc(sizeof(float)*Lx*Ly, 0);
  omp_target_memcpy(d_in, buffer, sizeof(float)*Lx*Ly, 0, 0, 0, 0);


  #pragma omp target synchronize
  double t0 = stop_watch(0);

  for(i=0; niter > i; i++) {
    dev_lapl_iter(d_out, d_in, xdelta, xnorm, Lx, Ly);
    std::swap(d_out, d_in);
  }

  #pragma omp target synchronize
  t0 = stop_watch(t0)/(double)niter;

  printf("Device: iters = %8d, (Lx,Ly) = %6d, %6d, t = %8.1f usec/iter, BW = %6.3f GB/s, P = %6.3f Gflop/s\n",
  	 niter, Lx, Ly, t0,
  	 Lx*Ly*sizeof(float)*2.0/(t0*1.0e3),
  	 (Lx*Ly*6.0)/(t0*1.0e3));


  omp_target_memcpy(d_res, d_in, sizeof(float)*Lx*Ly, 0, 0, 0, 0);


  bool ok = true;
  for (i = 0; Lx*Ly > i; i++) {

    if ( fabs(h_in[i] - d_res[i]) > 1e-2 ) {
      printf("Mismatch at %d cpu=%f gpu=%f\n", i, h_in[i], d_res[i]);
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  omp_target_free(d_in, 0);
  omp_target_free(d_out, 0);
  free(buffer);
  free(h_out);
  free(h_in);
  free(d_res);
  return 0;
}

#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <assert.h>
#include <sys/time.h>
#include <math.h>
#include <utility>
#include <omp.h>

#define NTX 16
#define NTY 16

double stop_watch(double t0)
{
  double time;
  struct timeval t;
  gettimeofday(&t, NULL);
  time = t.tv_sec * 1e6 + t.tv_usec;
  return time-t0;
}

void usage(char *argv[]) {
  fprintf(stderr, " Usage: %s LX LY NITER\n", argv[0]);
  return;
}

void reference(float *out, const float *in, const float delta, const float norm, const int Lx, const int Ly)
{
  #pragma omp parallel for collapse(2)
  for (int y = 0; Ly > y; y++) {
    for (int x = 0; Lx > x; x++) {
      int v00 = y*Lx + x;
      int v0p = y*Lx + (x + 1)%Lx;
      int v0m = y*Lx + (Lx + x - 1)%Lx;
      int vp0 = ((y+1)%Ly)*Lx + x;
      int vm0 = ((Ly+y-1)%Ly)*Lx + x;
      out[v00] = norm*in[v00] + delta*(in[v0p] + in[v0m] + in[vp0] + in[vm0]);
    }
  }
}

void dev_lapl_iter(float *out, const float *in, const float delta, const float norm, const int Lx, const int Ly)
{
  #pragma omp target teams distribute parallel for collapse(2)
  for (int y = 0; Ly > y; y++) {
    for (int x = 0; Lx > x; x++) {
      int v00 = y*Lx + x;
      int v0p = y*Lx + (x + 1)%Lx;
      int v0m = y*Lx + (Lx + x - 1)%Lx;
      int vp0 = ((y+1)%Ly)*Lx + x;
      int vm0 = ((Ly+y-1)%Ly)*Lx + x;
      out[v00] = norm*in[v00] + delta*(in[v0p] + in[v0m] + in[vp0] + in[vm0]);
    }
  }
}

int main(int argc, char *argv[]) {

  if(4 != argc) {
    usage(argv);
    exit(1);
  }


  int Lx = atoi(argv[1]);
  int Ly = atoi(argv[2]);
  if (0 != Lx % NTX ||  0 != Ly % NTY) {
    printf("Array length LX and LY must be a multiple of block size %d and %d, respectively\n",
          NTX, NTY);
    exit(1);
  }

  int niter = atoi(argv[3]);
  assert(niter >= 1);


  const float sigma = 0.01;
  const float xdelta = sigma / (1.0+4.0*sigma);
  const float xnorm = 1.0/(1.0+4.0*sigma);

  printf(" Ly,Lx = %d,%d\n", Ly, Lx);
  printf(" niter = %d\n", niter);


  srand(123);
  float *buffer = (float*) malloc(sizeof(float)*Lx*Ly);
  float *h_out = (float*) malloc(sizeof(float)*Lx*Ly);
  float *h_in  = (float*) malloc(sizeof(float)*Lx*Ly);
  float *d_res = (float*) malloc(sizeof(float)*Lx*Ly);

  int i, j, x, y;
  for (i = 0; Lx > i; i += 16) {
    x = rand() % Lx;
    for (j = 0; Ly > j; j++)
       buffer[x + j*Lx] = 1.f;
  }
  for (i = 0; Ly > i; i += 16) {
    y = rand() % Ly;
    for (j = 0; Lx > j; j++)
       buffer[j + y*Lx] = 1.f;
  }
  memcpy(h_in, buffer, sizeof(float)*Lx*Ly);

  for(i=0; niter > i; i++) {
    reference (h_out, h_in, xdelta, xnorm, Lx, Ly);
    std::swap(h_out, h_in);
  }


  float *d_in, *d_out;	
  int device = omp_get_default_device();
  d_in = (float*)omp_target_alloc(sizeof(float)*Lx*Ly, device);
  d_out = (float*)omp_target_alloc(sizeof(float)*Lx*Ly, device);
  omp_target_memcpy(d_in, buffer, sizeof(float)*Lx*Ly, 0, 0, device, omp_get_initial_device());


  #pragma omp target data use_device(d_in, d_out)
  {
    double t0 = stop_watch(0);

    for(i=0; niter > i; i++) {
      dev_lapl_iter(d_out, d_in, xdelta, xnorm, Lx, Ly);
      std::swap(d_out, d_in);
    }

    #pragma omp target end data
    t0 = stop_watch(t0)/(double)niter;

    printf("Device: iters = %8d, (Lx,Ly) = %6d, %6d, t = %8.1f usec/iter, BW = %6.3f GB/s, P = %6.3f Gflop/s\n",
    	 niter, Lx, Ly, t0,
    	 Lx*Ly*sizeof(float)*2.0/(t0*1.0e3),
    	 (Lx*Ly*6.0)/(t0*1.0e3));
  }


  omp_target_memcpy(d_res, d_in, sizeof(float)*Lx*Ly, 0, 0, omp_get_initial_device(), device);


  bool ok = true;
  for (i = 0; Lx*Ly > i; i++) {

    if ( fabs(h_in[i] - d_res[i]) > 1e-2 ) {
      printf("Mismatch at %d cpu=%f gpu=%f\n", i, h_in[i], d_res[i]);
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  omp_target_free(d_in, device);
  omp_target_free(d_out, device);
  free(buffer);
  free(h_out);
  free(h_in);
  free(d_res);
  return 0;
}

#include <chrono>
#include <cmath>
#include <cstdio>
#include <iostream>
#include <iomanip>
#include <limits>
#include <utility>
#include <omp.h>

#define N 2048

#define IDX(i, j) ((i) + (j) * N)

void initialize_data(float* f) {
  #pragma omp parallel for
  for (int j = 0; j < N; ++j) {
    for (int i = 0; i < N; ++i) {
      if (i == 0 || i == N-1) {
        f[IDX(i,j)] = sinf(j * 2 * M_PI / (N - 1));
      }
      else if (j == 0 || j == N-1) {
        f[IDX(i,j)] = sinf(i * 2 * M_PI / (N - 1));
      }
      else {
        f[IDX(i,j)] = 0.0f;
      }
    }
  }
}

void jacobi_step(float* f, const float* f_old, float* error) {
  #pragma omp target teams distribute parallel for thread_limit(256) reduction(+:*error)
  for (int j = 0; j < N; ++j) {
    for (int i = 0; i < N; ++i) {
      float f_old_tile[18][18];

      int local_i = i % 16;
      int local_j = j % 16;

      // Load center
      if (i < N && j < N) {
        f_old_tile[local_j+1][local_i+1] = f_old[IDX(i,j)];
      }

      // Load neighbors if on edge of tile
      if (local_i == 0 && i >= 1) {
        f_old_tile[local_j+1][local_i+0] = f_old[IDX(i-1,j)];
      }
      if (local_i == 15 && i <= N-2) {
        f_old_tile[local_j+1][local_i+2] = f_old[IDX(i+1,j)];
      }
      if (local_j == 0 && j >= 1) {
        f_old_tile[local_j+0][local_i+1] = f_old[IDX(i,j-1)];
      }
      if (local_j == 15 && j <= N-2) {
        f_old_tile[local_j+2][local_i+1] = f_old[IDX(i,j+1)];
      }

      float err = 0.0f;

      if (j >= 1 && j <= N-2 && i >= 1 && i <= N-2) {
        f[IDX(i,j)] = 0.25f * (f_old_tile[local_j+1][local_i+2] + 
                               f_old_tile[local_j+1][local_i+0] + 
                               f_old_tile[local_j+2][local_i+1] + 
                               f_old_tile[local_j+0][local_i+1]);
        float df = f[IDX(i,j)] - f_old_tile[local_j+1][local_i+1];
        err = df * df;
      }

      *error += err;
    }
  }
}

int main() {
  auto start_time = std::chrono::steady_clock::now();

  float* f = (float*) aligned_alloc(64, N * N * sizeof(float));
  float* f_old = (float*) aligned_alloc(64, N * N * sizeof(float));

  initialize_data(f);
  initialize_data(f_old);

  float* d_f;
  float* d_f_old;
  float* d_error;

  #pragma omp target enter data map(to: f[0:N*N], f_old[0:N*N]) map(alloc: d_f[0:N*N], d_f_old[0:N*N], d_error[0:1])
  {
    d_f = (float*) omp_target_alloc(N * N * sizeof(float), omp_get_default_device());
    d_f_old = (float*) omp_target_alloc(N * N * sizeof(float), omp_get_default_device());
    d_error = (float*) omp_target_alloc(sizeof(float), omp_get_default_device());

    #pragma omp target update to(d_f[0:N*N], d_f_old[0:N*N])

    float error = std::numeric_limits<float>::max();
    const float tolerance = 1.e-5f;

    const int max_iters = 10000;
    int num_iters = 0;

    auto start = std::chrono::steady_clock::now();

    while (error > tolerance && num_iters < max_iters) {
      float local_error = 0.0f;

      jacobi_step(d_f, d_f_old, &local_error);

      std::swap(d_f, d_f_old);

      error = sqrtf(local_error / (N * N));

      if (num_iters % 1000 == 0) {
        std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
      }

      ++num_iters;
    }

    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

    if (error <= tolerance && num_iters < max_iters) {
      std::cout << "PASS" << std::endl;
    }
    else {
      std::cout << "FAIL" << std::endl;
      #pragma omp target exit data map(release: d_f, d_f_old, d_error)
      free(f);
      free(f_old);
      return -1;
    }

    #pragma omp target update from(f[0:N*N])

    omp_target_free(d_f, omp_get_default_device());
    omp_target_free(d_f_old, omp_get_default_device());
    omp_target_free(d_error, omp_get_default_device());
  }

  free(f);
  free(f_old);

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}

