      }
    }
  }
}

void jacobi_step(float* f, const float* f_old, float* error) {
  int block_size = 16;

  #pragma omp parallel for collapse(2) schedule(static)
  for (int block_j = 0; block_j < N/block_size; ++block_j) {
    for (int block_i = 0; block_i < N/block_size; ++block_i) {
      int i_start = block_i * block_size;
      int j_start = block_j * block_size;

      float local_err = 0.0f;

      float f_old_tile[18][18];

      for (int tj = 0; tj < block_size; ++tj) {
        for (int ti = 0; ti < block_size; ++ti) {
          int i = i_start + ti;
          int j = j_start + tj;
          f_old_tile[tj+1][ti+1] = f_old[IDX(i,j)];

          if (ti == 0 && i >= 1) {
            f_old_tile[tj+1][ti] = f_old[IDX(i-1,j)];
          }
          if (ti == block_size-1 && i <= N-2) {
            f_old_tile[tj+1][ti+2] = f_old[IDX(i+1,j)];
          }
          if (tj == 0 && j >= 1) {
            f_old_tile[tj][ti+1] = f_old[IDX(i,j-1)];
          }
          if (tj == block_size-1 && j <= N-2) {
            f_old_tile[tj+2][ti+1] = f_old[IDX(i,j+1)];
          }
        }
      }

      for (int tj = 0; tj < block_size; ++tj) {
        for (int ti = 0; ti < block_size; ++ti) {
          int i = i_start + ti;
          int j = j_start + tj;

          if (j >= 1 && j <= N-2 && i >= 1 && i <= N-2) {
            f[IDX(i,j)] = 0.25f * (f_old_tile[tj+1][ti+2] + 
                                   f_old_tile[tj+1][ti] + 
                                   f_old_tile[tj+2][ti+1] + 
                                   f_old_tile[tj][ti+1]);
            float df = f[IDX(i,j)] - f_old_tile[tj+1][ti+1];
            local_err += df * df;
          }
        }
      }

      #pragma omp atomic
      *error += local_err;
    }
  }
}

int main() {
  auto start_time = std::chrono::steady_clock::now();

  float* f = (float*) aligned_alloc(64, N * N * sizeof(float));
  float* f_old = (float*) aligned_alloc(64, N * N * sizeof(float));
  float* d_f = (float*) aligned_alloc(64, N * N * sizeof(float));
