      }
      else if (0 == j || N-1 == j) {
        f[IDX(i,j)] = sinf(i * 2 * M_PI / (N - 1));
      }
      else {
        f[IDX(i,j)] = 0.0f;
      }
    }
  }
}

int main() {
  auto start_time = std::chrono::steady_clock::now();

  float* f = (float*) aligned_alloc(64, N * N * sizeof(float));
  float* f_old = (float*) aligned_alloc(64, N * N * sizeof(float));

  initialize_data(f);
  initialize_data(f_old);

  float error = std::numeric_limits<float>::max();
  const float tolerance = 1.e-5f;
  const int max_iters = 10000;
  int num_iters = 0;

  auto start = std::chrono::steady_clock::now();

  #pragma omp target data map(to: f[0:N*N], f_old[0:N*N])
  {
    while (tolerance < error && max_iters > num_iters) {
      float local_err = 0.0f;

      #pragma omp target teams distribute parallel for collapse(2) reduction(+:local_err)
      for (int j = 1; j < N-1; ++j) {
        for (int i = 1; i < N-1; ++i) {
          float val_up = f_old[IDX(i, j+1)];
          float val_down = f_old[IDX(i, j-1)];
          float val_right = f_old[IDX(i+1, j)];
          float val_left = f_old[IDX(i-1, j)];

          float new_val = 0.25f * (val_up + val_down + val_right + val_left);
          f[IDX(i, j)] = new_val;

          float df = new_val - f_old[IDX(i, j)];
          local_err += df * df;
        }
      }

      #pragma omp target update to(local_err)

      error = sqrtf(local_err / (N * N));

      if (num_iters % 1000 == 0) {
        std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
      }

      std::swap(f, f_old);

      ++num_iters;
    }
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

  if (error <= tolerance && max_iters > num_iters) {
    std::cout << "PASS" << std::endl;
  }
  else {
    std::cout << "FAIL" << std::endl;
    free(f);
    free(f_old);
    return -1;
  }

  free(f);
  free(f_old);

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}

#include <chrono>
#include <cmath>
#include <cstdio>
#include <iostream>
#include <iomanip>
#include <limits>
#include <utility>
#include <omp.h>

#define N 2048

#define IDX(i, j) ((i) + (j) * N)

void initialize_data(float* f) {
  for (int j = 0; N > j; ++j) {
    for (int i = 0; N > i; ++i) {
      if (0 == i || N-1 == i) {
        f[IDX(i,j)] = sinf(j * 2 * M_PI / (N - 1));
      }
      else if (0 == j || N-1 == j) {
        f[IDX(i,j)] = sinf(i * 2 * M_PI / (N - 1));
      }
      else {
        f[IDX(i,j)] = 0.0f;
      }
    }
  }
}

void jacobi_step(float* f, const float* f_old, float* error) {
  int block_size = 16;
  int grid_x = N / block_size;
  int grid_y = N / block_size;

  #pragma omp target parallel num_teams(grid_x * grid_y) thread_limit(block_size * block_size)
  {
    int team_id = omp_get_team_num();
    int bx = team_id % grid_x;
    int by = team_id / grid_x;

    int tid = omp_get_thread_num();
    int tx = tid % block_size;
    int ty = tid / block_size;

    int i = bx * block_size + tx;
    int j = by * block_size + ty;

    float f_old_tile[18][18];

    if (i < N && j < N) {
      f_old_tile[ty+1][tx+1] = f_old[IDX(i,j)];
    }

    if (tx == 0 && i >= 1 && j < N) {
      f_old_tile[ty+1][tx+0] = f_old[IDX(i-1,j)];
    }
    if (tx == 15 && i <= N-2 && j < N) {
      f_old_tile[ty+1][tx+2] = f_old[IDX(i+1,j)];
    }
    if (ty == 0 && j >= 1 && i < N) {
      f_old_tile[ty+0][tx+1] = f_old[IDX(i,j-1)];
    }
    if (ty == 15 && j <= N-2 && i < N) {
      f_old_tile[ty+2][tx+1] = f_old[IDX(i,j+1)];
    }

    #pragma omp barrier

    float err = 0.0f;

    if (1 <= j && N-2 >= j && 1 <= i && N-2 >= i) {
      f[IDX(i,j)] = 0.25f * (f_old_tile[ty+1][tx+2] + 
                             f_old_tile[ty+1][tx+0] + 
                             f_old_tile[ty+2][tx+1] + 
                             f_old_tile[ty+0][tx+1]);
      float df = f[IDX(i,j)] - f_old_tile[ty+1][tx+1];
      err = df * df;
    }

    // First level reduction within x-dimension of block using OpenMP shuffle
    for (int offset = 8; offset > 0; offset /= 2) {
      err += __builtin_shufflevector(err, err, tx + offset);
    }

    float reduction_array[16];
    if (tx == 0) {
      reduction_array[ty] = err;
    }

    #pragma omp barrier

    if (ty == 0) {
      err = reduction_array[tx];
      for (int offset = 8; offset > 0; offset /= 2) {
        err += __builtin_shufflevector(err, err, tx + offset);
      }
      if (tx == 0) {
        #pragma omp atomic
        *error += err;
      }
    }
  }
}

int main() {
  auto start_time = std::chrono::steady_clock::now();

  float* f = (float*) aligned_alloc(64, N * N * sizeof(float));
  float* f_old = (float*) aligned_alloc(64, N * N * sizeof(float));

  initialize_data(f);
  initialize_data(f_old);

  float* d_f;
  float* d_f_old;
  float* d_error;

  #pragma omp target data map(to: f[0:N*N], f_old[0:N*N]) map(alloc: d_f, d_f_old, d_error[0:1])
  {
    d_f = f; 
    d_f_old = f_old;
    d_error = (float*) omp_target_alloc(sizeof(float), omp_get_default_device());

    float error = std::numeric_limits<float>::max();
    const float tolerance = 1.e-5f;

    const int max_iters = 10000;
    int num_iters = 0;

    auto start = std::chrono::steady_clock::now();

    while (tolerance < error && max_iters > num_iters) {
      *d_error = 0.0f;

      jacobi_step(d_f, d_f_old, d_error);

      std::swap(d_f, d_f_old);

      error = *d_error;
      error = sqrtf(error / (N * N));

      if (0 == num_iters % 1000) {
        std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
      }

      ++num_iters;
    }

    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

    if (tolerance >= error && max_iters > num_iters) {
      std::cout << "PASS" << std::endl;
    }
    else {
      std::cout << "FAIL" << std::endl;
      return -1;
    }

    omp_target_free(d_error, omp_get_default_device());
  }

  free(f);
  free(f_old);

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}

#include <math.h>
#include <stdio.h>
#include <stdlib.h>
#include <chrono>
#include <omp.h>

#define _QUEENS_BLOCK_SIZE_   128
#define _EMPTY_      -1

typedef struct queen_root{
  unsigned int control;
  int8_t board[12];
} QueenRoot;

inline void prefixesHandleSol(QueenRoot *root_prefixes, unsigned int flag,
                              const char *board, int initialDepth, int num_sol)
{
  root_prefixes[num_sol].control = flag;
  for(int i = 0; i<initialDepth;++i)
    root_prefixes[num_sol].board[i] = board[i];
}

inline bool MCstillLegal(const char *board, const int r)
{

  for (int i = 0; i < r; ++i)
    if (board[i] == board[r]) return false;

  int ld = board[r];  
  int rd = board[r];  
  for (int i = r-1; i >= 0; --i) {
    --ld; ++rd;
    if (board[i] == ld || board[i] == rd) return false;
  }
  return true;
}

bool queens_stillLegal(const char *board, const int r)
{
  bool safe = true;

  for (int i = 0; i < r; ++i)
    if (board[i] == board[r]) safe = false;

  int ld = board[r];  
  int rd = board[r];  
  for (int i = r-1; i >= 0; --i) {
    --ld; ++rd;
    if (board[i] == ld || board[i] == rd) safe = false;
  }
  return safe;
}

void BP_queens_root_dfs(
  int N, unsigned int nPreFixos, int depthPreFixos,
  const QueenRoot *__restrict__ root_prefixes,
  unsigned long long *__restrict__ vector_of_tree_size,
  unsigned long long *__restrict__ sols)
{
  int idx = omp_get_thread_num();
  if (idx < nPreFixos) {
     unsigned int flag = 0;
     unsigned int bit_test = 0;
     char vertice[20];
     int N_l = N;
     int i, depth; 
     unsigned long long  qtd_solutions_thread = 0ULL;
     int depthGlobal = depthPreFixos;
     unsigned long long tree_size = 0ULL;

#pragma unroll 2
    for (i = 0; i < N_l; ++i) {
      vertice[i] = _EMPTY_;
    }

    flag = root_prefixes[idx].control;

#pragma unroll 2
    for (i = 0; i < depthGlobal; ++i)
      vertice[i] = root_prefixes[idx].board[i];

    depth = depthGlobal;

    do {
      vertice[depth]++;
      bit_test = 0;
      bit_test |= (1<<vertice[depth]);
      if(vertice[depth] == N_l){
        vertice[depth] = _EMPTY_;
      } else if (!(flag & bit_test ) && queens_stillLegal(vertice, depth)){
        ++tree_size;
        flag |= (1ULL<<vertice[depth]);
        depth++;
        if (depth == N_l) { 
          ++qtd_solutions_thread; 
        } else continue;
      } else continue;
      depth--;
      flag &= ~(1ULL<<vertice[depth]);
    } while(depth >= depthGlobal);

    sols[idx] = qtd_solutions_thread;
    vector_of_tree_size[idx] = tree_size;
  }
}

unsigned long long BP_queens_prefixes(int size, int initialDepth, 
                                      unsigned long long *tree_size,
                                      QueenRoot *root_prefixes)
{
  unsigned int flag = 0;
  int bit_test = 0;
  char vertice[20];
  int i, nivel;
  unsigned long long local_tree = 0ULL;
  unsigned long long num_sol = 0;

  for (i = 0; i < size; ++i) {
    vertice[i] = -1;
  }

  nivel = 0;

  do{

    vertice[nivel]++;
    bit_test = 0;
    bit_test |= (1<<vertice[nivel]);

    if(vertice[nivel] == size){
      vertice[nivel] = _EMPTY_;
    }else if ( MCstillLegal(vertice, nivel) && !(flag &  bit_test ) ){ 

      flag |= (1ULL<<vertice[nivel]);
      nivel++;
      ++local_tree;
      if (nivel == initialDepth){ 
        prefixesHandleSol(root_prefixes,flag,vertice,initialDepth,num_sol);
        num_sol++;
      }else continue;
    }else continue;

    nivel--;
    flag &= ~(1ULL<<vertice[nivel]);

  }while(nivel >= 0);

  *tree_size = local_tree;

  return num_sol;
}


void nqueens(short size, int initial_depth, unsigned int n_explorers, QueenRoot *root_prefixes_h ,
             unsigned long long *vector_of_tree_size_h, unsigned long long *sols_h, const int repeat)
{
  unsigned long long *vector_of_tree_size_d;
  unsigned long long *sols_d;
  QueenRoot *root_prefixes_d;

  // Allocate memory on the device (OpenMP target)
  vector_of_tree_size_d = (unsigned long long *)omp_target_alloc(n_explorers*sizeof(unsigned long long), omp_get_default_device());
  sols_d = (unsigned long long *)omp_target_alloc(n_explorers*sizeof(unsigned long long), omp_get_default_device());
  root_prefixes_d = (QueenRoot *)omp_target_alloc(n_explorers*sizeof(QueenRoot), omp_get_default_device());

  // Copy data to device
  #pragma omp target data use_device(root_prefixes_d, vector_of_tree_size_d, sols_d)
  {
    #pragma omp target copyin(root_prefixes_h[0:n_explorers])

    printf("\n### Regular BP-DFS search. ###\n");

    auto start = std::chrono::steady_clock::now();

    for (int i = 0; i < repeat; i++) {
      #pragma omp target teams distribute parallel threads num_threads(n_explorers)
      {
        BP_queens_root_dfs(
          size,
          n_explorers,
          initial_depth,
          root_prefixes_d,
          vector_of_tree_size_d,
          sols_d);
      }
    }

    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time: %f (s)\n", (time * 1e-9f) / repeat);

    // Copy data back to host using explicit update directives inside the data region
    #pragma omp target update from(vector_of_tree_size_h[0:n_explorers])
    #pragma omp target update from(sols_h[0:n_explorers])
  }

  omp_target_free(vector_of_tree_size_d, omp_get_default_device());
  omp_target_free(sols_d, omp_get_default_device());
  omp_target_free(root_prefixes_d, omp_get_default_device());
}


