  for (int j = 0; j < iteration; j++)
  {
    md_offload(d_position, d_force, d_neighborList,
      nAtom, maxNeighbors, lj1, lj2, cutsq);
  }

  #pragma omp target data use_device(d_force)
  {
    #pragma omp target update to(h_force[0:nAtom])
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average kernel execution time " << (time * 1e-9f) / iteration << " (s)\n";

  omp_target_free(d_position, omp_get_default_device());
  omp_target_free(d_force, omp_get_default_device());
  omp_target_free(d_neighborList, omp_get_default_device());

  free(position);
  free(h_force);
  free(neighborList);

  return 0;
}

