      int j = 0;
      while (maxNeighbors > j)
      {
        int jidx = neighborList[j*nAtom + idx];

        POSVECTYPE jpos = position[jidx];

        FPTYPE delx = ipos.x - jpos.x;
        FPTYPE dely = ipos.y - jpos.y;
        FPTYPE delz = ipos.z - jpos.z;
        FPTYPE r2inv = delx*delx + dely*dely + delz*delz;

        if (0 < r2inv && cutsq_t > r2inv)
        {
          r2inv = (FPTYPE)1.0 / r2inv;
          FPTYPE r6inv = r2inv * r2inv * r2inv;
          FPTYPE forceC = r2inv * r6inv * (lj1_t * r6inv - lj2_t);

          f.x += delx * forceC;
          f.y += dely * forceC;
          f.z += delz * forceC;
        }
        j++;
      }
      force[idx] = f;
    }
  }
}

int main(int argc, char** argv)
{
  if (3 != argc) {
    std::cout << "Usage: ./" << argv[0] << " <class size> <iteration>\n";
    return 1;
  }

  int sizeClass = atoi(argv[1]);
  int iteration = atoi(argv[2]);
  const int probSizes[] = { 12288, 24576, 36864, 73728 };
  assert(sizeClass >= 0 && sizeClass < 4);
  assert(iteration >= 0);

  int nAtom = probSizes[sizeClass];

  POSVECTYPE* position = (POSVECTYPE*) malloc(nAtom * sizeof(POSVECTYPE));
  FORCEVECTYPE* h_force = (FORCEVECTYPE*) malloc(nAtom * sizeof(FORCEVECTYPE));
  int *neighborList = (int*) malloc(maxNeighbors * nAtom * sizeof(int));

  std::cout << "Initializing test problem (this can take several minutes for large problems).\n";

  srand(123);

  for (int i = 0; nAtom > i; i++)
  {
    position[i].x = rand() % domainEdge;
    position[i].y = rand() % domainEdge;
    position[i].z = rand() % domainEdge;
  }

  std::cout << "Finished.\n";
  int totalPairs = buildNeighborList<FPTYPE, POSVECTYPE>(nAtom, position, neighborList);
  std::cout << totalPairs << " of " << nAtom*maxNeighbors << " pairs within cutoff distance = " 
       << 100.0 * ((double)totalPairs / (nAtom*maxNeighbors)) << " %\n";

  POSVECTYPE*   d_position;
  FORCEVECTYPE* d_force;
  int* d_neighborList;

  d_force = (FORCEVECTYPE*) omp_target_alloc(nAtom * sizeof(FORCEVECTYPE), 0);
  d_position = (POSVECTYPE*) omp_target_alloc(nAtom * sizeof(POSVECTYPE), 0);
  d_neighborList = (int*) omp_target_alloc(nAtom * maxNeighbors * sizeof(int), 0);

  omp_target_memcpy(d_position, position, nAtom * sizeof(POSVECTYPE), 0, 0, 0, 0);
  omp_target_memcpy(d_neighborList, neighborList, nAtom * maxNeighbors * sizeof(int), 0, 0, 0, 0);

  #pragma omp target data map(to: d_position[0:nAtom], d_neighborList[0:nAtom*maxNeighbors]) map(from: d_force[0:nAtom])
  {
    md(d_position, d_force, d_neighborList,
        nAtom, maxNeighbors, lj1, lj2, cutsq);

    omp_target_memcpy(h_force, d_force, nAtom * sizeof(FORCEVECTYPE), 0, 0, 0, 0);
  }

  std::cout << "Performing Correctness Check (may take several minutes)\n";

  checkResults<FPTYPE, FORCEVECTYPE, POSVECTYPE>(h_force, position, neighborList, nAtom);

  auto start = std::chrono::steady_clock::now();

  #pragma omp target data map(to: d_position[0:nAtom], d_neighborList[0:nAtom*maxNeighbors]) map(from: d_force[0:nAtom])
  {
    for (int j = 0; iteration > j; j++)
    {
      md(d_position, d_force, d_neighborList,
        nAtom, maxNeighbors, lj1, lj2, cutsq);
    }
  }

  #pragma omp target update host(d_force[0:nAtom])

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average kernel execution time " << (time * 1e-9f) / iteration << " (s)\n";

  omp_target_free(d_position, 0);
  omp_target_free(d_force, 0);
  omp_target_free(d_neighborList, 0);

  free(position);
  free(h_force);
  free(neighborList);

  return 0;
}

#include <assert.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <chrono>
#include <omp.h>

#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

template<typename T>
T mask_const[MAX_MASK_WIDTH];

template<typename T>
void conv1d(const T * __restrict__ in,
            T * __restrict__ out,
            const int input_width,
            const int mask_width,
            const T * __restrict__ d_mask)
{
  #pragma omp target parallel for
  {
    int i = omp_get_thread_num();
    if (i < input_width) {
      T s = 0;
      int start = i - mask_width / 2;
      for (int j = 0; j < mask_width; j++) {
        if (start + j >= 0 && start + j < input_width) {
          s += in[start + j] * d_mask[j];
        }
      }
      out[i] = s;
    }
  }
}

template<typename T>
void conv1d_tiled(const T *__restrict__ in,
                  T *__restrict__ out,
                  const int input_width,
                  const int mask_width,
                  const T * __restrict__ d_mask,
                  int block_size)
{
  int n = mask_width / 2;
  int num_blocks = (input_width + block_size - 1) / block_size;

  #pragma omp target parallel for
  {
    int block_idx = omp_get_thread_num();

    if (block_idx < num_blocks) {
      int tid; 
      T tile[MAX_BLOCK_SIZE + MAX_MASK_WIDTH];

      int base_idx = block_idx * block_size;

      for (tid = 0; tid < block_size; tid++) {
        int idx = base_idx + tid;
        if (idx < input_width) tile[n + tid] = in[idx];
        else tile[n + tid] = 0;
      }

      for (tid = 0; tid < n; tid++) {
        int halo_left = (block_idx - 1) * block_size + tid;
        if (halo_left < 0) tile[tid] = 0;
        else if (halo_left < input_width) tile[tid] = in[halo_left];
        else tile[tid] = 0;
      }

      for (tid = 0; tid < n; tid++) {
        int halo_right = (block_idx + 1) * block_size + tid;
        if (halo_right >= input_width) tile[block_size + n + tid] = 0;
        else if (halo_right < input_width) tile[block_size + n + tid] = in[halo_right];
        else tile[block_size + n + tid] = 0;
      }

      for (tid = 0; tid < block_size; tid++) {
        int i = base_idx + tid;
        if (i < input_width) {
          T s = 0;
          for (int j = 0; j < mask_width; j++) {
            s += tile[tid + j] * d_mask[j];
          }
          out[i] = s;
        }
      }
    }
  }
}

template<typename T>
void conv1d_tiled_caching(const T *__restrict__ in,
                          T *__restrict__ out,
                          const int input_width,
                          const int mask_width,
                          const T * __restrict__ d_mask,
                          int block_size)
{
  int num_blocks = (input_width + block_size - 1) / block_size;
  int n = mask_width / 2;

  #pragma omp target parallel for
  {
    int block_idx = omp_get_thread_num();

    if (block_idx < num_blocks) {
      int base_idx = block_idx * block_size;
      int next_base_idx = (block_idx + 1) * block_size;

      T tile[MAX_BLOCK_SIZE];
      for (int tid = 0; tid < block_size; tid++) {
        int idx = base_idx + tid;
        if (idx < input_width) tile[tid] = in[idx];
        else tile[tid] = 0;
      }

      for (int tid = 0; tid < block_size; tid++) {
        int i = base_idx + tid;
        if (i < input_width) {
          int start = i - n;
          T s = 0;
          for (int j = 0; j < mask_width; j++) {
            int in_index = start + j;
            if (in_index >= 0 && in_index < input_width) {
              if (in_index >= base_idx && in_index < next_base_idx) {
                s += tile[in_index - base_idx] * d_mask[j];
              } else {
                s += in[in_index] * d_mask[j];
              }
            }
          }
          out[i] = s;
        }
      }
    }
  }
}

template <typename T>
void reference(const T *h_in,
               const T *d_out,
               const T *mask,
               const int input_width,
               const int mask_width)
{
  bool ok = true;
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += h_in[start + j] * mask[j];
      }
    }
    if (fabs(s - d_out[i]) > 1e-3) {
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");
}

template <typename T>
void conv1D(const int input_width, const int mask_width, const int repeat)
{
  size_t size_bytes = input_width * sizeof(T);

  T *a, *b;
  a = (T *)malloc(size_bytes); 
  b = (T *)malloc(size_bytes); 

  T h_mask[MAX_MASK_WIDTH];
  for (int i = 0; i < MAX_MASK_WIDTH; i++) h_mask[i] = 1; 

  srand(123);
  for (int i = 0; i < input_width; i++) {
    a[i] = rand() % 256;
  }

  T *d_a, *d_b;

  #pragma omp target data map(to: a[0:input_width]) map(alloc: d_a[0:input_width], d_b[0:input_width])
  {
    d_a = (T *)omp_target_alloc(size_bytes, omp_get_default_device());
    d_b = (T *)omp_target_alloc(size_bytes, omp_get_default_device());

    omp_target_memcpy(d_a, a, size_bytes, 0, 0, omp_get_default_device(), omp_get_initial_device());

    for (int i = 0; i < mask_width; i++) {
      mask_const<T>[i] = h_mask[i];
    }

    for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
      auto start = std::chrono::steady_clock::now();
      for (int i = 0; i < repeat; i++) {
        conv1d<T>(d_a, d_b, input_width, mask_width, mask_const<T>);
      }
      auto end = std::chrono::steady_clock::now();
      auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
      printf("Average kernel execution time of conv1d kernel (block size %d): %f (us)\n",
             bs, (time * 1e-3f) / repeat);

      omp_target_memcpy(b, d_b, size_bytes, 0, 0, omp_get_initial_device(), omp_get_default_device());
      reference(a, b, h_mask, input_width, mask_width);
    }

    for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
      auto start = std::chrono::steady_clock::now();
      for (int i = 0; i < repeat; i++) {
        conv1d_tiled<T>(d_a, d_b, input_width, mask_width, mask_const<T>, bs);
      }
      auto end = std::chrono::steady_clock::now();
      auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
      printf("Average kernel execution time of conv1d-tiled kernel (block size %d): %f (us)\n",
             bs, (time * 1e-3f) / repeat);

      omp_target_memcpy(b, d_b, size_bytes, 0, 0, omp_get_initial_device(), omp_get_default_device());
      reference(a, b, h_mask, input_width, mask_width);
    }

    for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
      auto start = std::chrono::steady_clock::now();
      for (int i = 0; i < repeat; i++) {
        conv1d_tiled_caching<T>(d_a, d_b, input_width, mask_width, mask_const<T>, bs);
      }
      auto end = std::chrono::steady_clock::now();
      auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
      printf("Average kernel execution time of conv1d-tiled-caching kernel (block size %d): %f (us)\n",
             bs, (time * 1e-3f) / repeat);

      omp_target_memcpy(b, d_b, size_bytes, 0, 0, omp_get_initial_device(), omp_get_default_device());
      reference(a, b, h_mask, input_width, mask_width);
    }
  }

  free(a);
  free(b);
}

int main(int argc, char* argv[]) {
  if (argc != 3) {
    printf("Usage: %s <input_width> <repeat>\n", argv[0]);
    return 1;
  }

  int input_width = atoi(argv[1]);
  input_width = (input_width + MAX_BLOCK_SIZE - 1) / MAX_BLOCK_SIZE * MAX_BLOCK_SIZE;

  const int repeat = atoi(argv[2]);

  for (int mask_width = 3; mask_width < MAX_MASK_WIDTH; mask_width += 2) {
    printf("\n---------------------\n");
    printf("Mask width: %d\n", mask_width); 

    printf("1D convolution (FP64)\n");
    conv1D<double>(input_width, mask_width, repeat);

    printf("1D convolution (FP32)\n");
    conv1D<float>(input_width, mask_width, repeat);

    printf("1D convolution (INT16)\n");
    conv1D<int16_t>(input_width, mask_width, repeat);
  }

  return 0;
}

