  for (int block_idx = 0; block_idx < num_blocks; block_idx++) {
    T tile_local[MAX_BLOCK_SIZE + 2 * MAX_MASK_WIDTH]; 
    int start_block = block_idx * block_size;

    int halo_left_idx = (block_idx - 1) * block_size;
    for (int t_idx = 0; t_idx < block_size; t_idx++) {
      int global_idx = start_block + t_idx;

      if (t_idx >= block_size - n) {
        int halo_left = halo_left_idx + t_idx;
        tile_local[t_idx - (block_size - n)] = (halo_left < 0 || halo_left >= input_width) ? 0 : in[halo_left];
      }

      tile_local[n + t_idx] = (global_idx >= input_width) ? 0 : in[global_idx];

      if (t_idx < n) {
        int halo_right = (block_idx + 1) * block_size + t_idx;
        tile_local[t_idx + block_size + n] = (halo_right >= input_width || halo_right < 0) ? 0 : in[halo_right];
      }
    }

    for (int t_idx = 0; t_idx < block_size; t_idx++) {
      int i = start_block + t_idx;
      if (i >= input_width) continue;

      T s = 0;
      for (int j = 0; j < mask_width; j++) {
        s += tile_local[t_idx + j] * mask<T>[j];
      }
      out[i] = s;
    }
  }
}

