  int i;
  for(i=0; n > i; ++i){
    a[i] = val;
  }
}

void usage(char *argv[]){
  fprintf(stderr, "Usage: %s [-n number of pages] [-i max iterations]"
                  " [-t threshold] [-q divisor for zero density]\n", argv[0]);
}

static struct option size_opts[] =
{

  {"number of pages", 1, NULL, 'n'},
  {"max number of iterations", 1, NULL, 'i'},
  {"minimum threshold", 1, NULL, 't'},
  {"divisor for zero density", 1, NULL, 'q'},
  { 0, 0, 0}
};

float maximum_dif(float *difs, int n){
  int i;
  float max = 0.0f;
  for(i=0; n > i; ++i){
    max = max < difs[i] ? difs[i] : max;
  }
  return max;
}

int main(int argc, char *argv[]) {
  int *pages;
  float *maps;
  float *page_ranks;
  unsigned int *noutlinks;
  int t;
  float max_diff, max_diff_ref;

  int i = 0;
  int j;
  int n = 1000;
  int iter = max_iter;
  float thresh = threshold;
  int divisor = 2;

  int opt, opt_index = 0;
  while((opt = getopt_long(argc, argv, "::n:i:t:q:", size_opts, &opt_index)) != -1){
    switch(opt){
      case 'n':
        n = atoi(optarg);
        break;
      case 'i':
        iter = atoi(optarg);
        break;
      case 't':
        thresh = atof(optarg);
        break;
      case 'q':
        divisor = atoi(optarg);
        break;
      default:
        usage(argv);
        exit(EXIT_FAILURE);
    }
  }

  size_t rank_size = (size_t)n * sizeof(float);
  size_t map_size = (size_t)n * n * sizeof(float);
  size_t page_size = (size_t)n * n * sizeof(int);
  size_t link_size = (size_t)n * sizeof(unsigned int);

  page_ranks = (float*)malloc(rank_size);
  maps = (float*)malloc(map_size);
  noutlinks = (unsigned int*)malloc(link_size);

  max_diff=max_diff_ref=99.0f;

  for (i=0; n > i; ++i) {
    noutlinks[i] = 0;
  }
  pages = random_pages(n,noutlinks,divisor);
  init_array(page_ranks, n, 1.0f / (float) n);

  float *diffs;
  diffs = (float*) malloc(rank_size);

  int *d_pages;
  float *d_maps;
  float *d_page_ranks;
  float *d_diffs;
  unsigned int *d_noutlinks;

  // Allocate on the default device (device 0)
  d_pages = (int*)omp_target_alloc(page_size, 0);
  d_page_ranks = (float*)omp_target_alloc(rank_size, 0);
  d_maps = (float*)omp_target_alloc(map_size, 0);
  d_noutlinks = (unsigned int*)omp_target_alloc(link_size, 0);
  d_diffs = (float*)omp_target_alloc(rank_size, 0);

  if (!d_pages || !d_page_ranks || !d_maps || !d_noutlinks || !d_diffs) {
      fprintf(stderr, "ERROR: Failed to allocate memory on device\n");
      free(pages); free(maps); free(page_ranks); free(noutlinks); free(diffs);
      return 1;
  }

  // Initialize d_diffs to 0 on device using a target construct
  #pragma omp target teams distribute parallel for
  for (size_t k = 0; k < (rank_size / sizeof(float)); k++) {
      d_diffs[k] = 0.0f;
  }

  // Copy data from host to device using omp_target_memcpy
  // Arguments: dst, src, size, dst_device, src_device, dst_device_async, src_device_async
  // dst_device=0 (GPU), src_device=omp_target_device_host (-1)
  omp_target_memcpy(d_pages, pages, page_size, 0, omp_target_device_host, 0, 0);
  omp_target_memcpy(d_page_ranks, page_ranks, rank_size, 0, omp_target_device_host, 0, 0);
  omp_target_memcpy(d_noutlinks, noutlinks, link_size, 0, omp_target_device_host, 0, 0);

  double ktime = 0.0;
  printf("Threshold: %f\n", thresh);

  for (t=1; iter >= t && thresh <= max_diff; ++t) {
    auto start = std::chrono::high_resolution_clock::now();

    map_offload(d_pages, d_page_ranks, d_maps, d_noutlinks, n);
    reduce_offload(d_page_ranks, d_maps, n, d_diffs);

    auto end = std::chrono::high_resolution_clock::now();
    ktime += std::chrono::duration_cast<std::chrono::duration<double>>(end - start).count();

    // Copy diffs back to host
    omp_target_memcpy(diffs, d_diffs, rank_size, omp_target_device_host, 0, 0, 0);
    max_diff = maximum_dif(diffs, n);
  }



  omp_target_free(d_pages, 0);
  omp_target_free(d_maps, 0);
  omp_target_free(d_page_ranks, 0);
  omp_target_free(d_noutlinks, 0);
  omp_target_free(d_diffs, 0);

  fprintf(stderr, "Max difference %f is reached at iteration %d\n", max_diff, t);
  printf("\"Options\": \"-n %d -i %d -t %f\". Total kernel execution time: %lf (s)\n",
         n, iter, thresh, ktime);

  memset(diffs, 0, rank_size);
  for (t=1; iter >= t && thresh <= max_diff_ref; ++t) {
    map_ref(pages, page_ranks, maps, noutlinks, n);
    reduce_ref(page_ranks, maps, n, diffs);
    max_diff_ref = maximum_dif(diffs, n);
  }
  bool ok = fabsf(max_diff - max_diff_ref) < 1e-3f;
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(pages);
  free(maps);
  free(page_ranks);
  free(noutlinks);
  free(diffs);

  return 0;
}
